const _baseGuessTheMusicNotationQuestions: Question[] = [
  q(6_135_001, 'Clefs', 'Treble clef', 'Which symbol marks the staff for higher-pitched notes and curls around the G line?', 'Treble clef', [['Bass clef', 'The bass clef locates F for lower-pitched notes; it does not curl around the G line for higher pitches.'], ['Sharp sign', 'A sharp is an accidental that raises a pitch by a semitone; it is not a clef defining staff pitch.'], ['Rest', 'A rest marks silence and is not a clef at all.']], 'The treble clef is also called the G clef because it locates G on the staff.', 'kids', media('treble clef', 'high notes', 'G line', '#8e6f9e', 'notation')),
  q(6_135_002, 'Clefs', 'Bass clef', 'Which symbol marks lower-pitched notes and has two dots around the F line?', 'Bass clef', [['Treble clef', 'The treble clef locates G for higher-pitched notes; it does not bracket the F line with two dots.'], ['Flat sign', 'A flat is an accidental that lowers a pitch by a semitone; it is not a clef.'], ['Time signature', 'A time signature shows how beats group within a measure; it does not define staff pitch.']], 'The bass clef is also called the F clef because its dots surround the F line.', 'kids', media('bass clef', 'low notes', 'F line', '#5d6d7e', 'notation')),
  q(6_135_003, 'Accidentals', 'Sharp sign', 'Which symbol raises a note by a half step?', 'Sharp', [['Flat', 'A flat lowers a pitch by a half step rather than raising it.'], ['Natural', 'A natural cancels a previous accidental; it does not raise the pitch.'], ['Rest', 'A rest marks silence and does not change pitch at all.']], 'A sharp raises a pitch by one semitone in standard notation.', 'kids', media('sharp', 'raises note', 'half step', '#34495e', 'notation')),
  q(6_135_004, 'Accidentals', 'Flat sign', 'Which symbol lowers a note by a half step?', 'Flat', [['Sharp', 'A sharp raises a pitch by a half step, the opposite of a flat.'], ['Natural', 'A natural cancels a previous accidental; it does not lower the pitch on its own.'], ['Repeat sign', 'A repeat sign marks a section to repeat; it does not alter pitch.']], 'A flat lowers a pitch by one semitone in standard notation.', 'kids', media('flat', 'lowers note', 'half step', '#3498db', 'notation')),
  q(6_135_005, 'Rhythm', 'Quarter note', 'Which note value usually gets one beat in common time?', 'Quarter note', [['Whole note', 'A whole note typically lasts four beats in common time, not one.'], ['Eighth rest', 'An eighth rest is silence for half a beat; it is not a one-beat note.'], ['Tie', 'A tie links two notes into one sustained sound; it is not a note value itself.']], 'In 4/4 time, a quarter note commonly equals one beat.', 'kids', media('quarter note', 'one beat', 'filled head', '#2f8f6f', 'notation')),
  q(6_135_006, 'Rhythm', 'Eighth note flag', 'Which note value is half of a quarter note and often has a flag or beam?', 'Eighth note', [['Half note', 'A half note is twice the length of a quarter note, not half.'], ['Whole note', 'A whole note is four times the length of a quarter; it is far longer than the value described.'], ['Fermata', 'A fermata indicates holding a note longer than written; it is not a specific note value.']], 'Eighth notes divide a beat into two equal parts in common simple meters.', 'adults', media('eighth note', 'flag', 'half beat', '#f39c12', 'notation')),
  q(6_135_007, 'Silence', 'Rest symbol', 'Which notation symbol tells the musician to be silent for a duration?', 'Rest', [['Tie', 'A tie joins two pitched notes; it does not indicate silence.'], ['Slur', 'A slur marks legato connection between pitched notes; it does not call for silence.'], ['Accent', 'An accent emphasizes a sounding note; it is not a sign of silence.']], 'A rest marks silence for a specific rhythmic value.', 'kids', media('rest', 'silence', 'duration', '#7f8c8d', 'notation')),
  q(6_135_008, 'Structure', 'Time signature', 'Which notation marking tells how beats are grouped in each measure?', 'Time signature', [['Key signature', 'A key signature shows which notes are sharp or flat throughout the piece, not how beats group per measure.'], ['Treble clef', 'A treble clef defines staff pitch; it says nothing about meter or beat grouping.'], ['Dynamic marking', 'A dynamic marking sets loudness, not how beats are grouped.']], 'A time signature shows the meter, such as how many beats are in a measure and which note value gets the beat.', 'adults', media('time signature', 'beats', 'measure', '#c0392b', 'notation')),
]

